import{_ as e,o as t,c as i,a2 as o}from"./chunks/framework.BFVZdVmd.js";const d=JSON.parse('{"title":"OAuth2 与 JWT","description":"","frontmatter":{},"headers":[],"relativePath":"security/oauth2-jwt.md","filePath":"security/oauth2-jwt.md","lastUpdated":null}'),n={name:"security/oauth2-jwt.md"};function s(l,a,r,c,h,p){return t(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="oauth2-与-jwt" tabindex="-1">OAuth2 与 JWT <a class="header-anchor" href="#oauth2-与-jwt" aria-label="Permalink to &quot;OAuth2 与 JWT&quot;">​</a></h1><blockquote><p>OAuth2 是授权协议，JWT 是 Token 格式，二者常配合 Spring Security 构成标准认证方案。</p></blockquote><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><ul><li><strong>OAuth2</strong>：授权协议，定义了第三方应用获取资源访问权限的标准流程。</li><li><strong>JWT</strong>：JSON Web Token，一种自包含的 Token 格式，服务端无需存储会话即可校验。</li><li><strong>Spring Authorization Server</strong>：Spring 官方的 OAuth2 授权服务器实现。</li><li><strong>Keycloak</strong>：开源身份认证系统，提供完整的 IAM 能力。</li></ul><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><ul><li>统一登录认证与单点登录（SSO）</li><li>无状态 Token 校验，便于微服务横向扩展</li><li>标准化的授权流程，便于对接第三方</li></ul><h2 id="标准方案" tabindex="-1">标准方案 <a class="header-anchor" href="#标准方案" aria-label="Permalink to &quot;标准方案&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Spring Security + OAuth2 + JWT</span></span></code></pre></div><p>典型流程：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户登录 -&gt; 认证中心签发 JWT</span></span>
<span class="line"><span>请求携带 JWT -&gt; Gateway 校验</span></span>
<span class="line"><span>业务服务从 Token 解析用户上下文</span></span></code></pre></div><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>标准企业方案：<code>Spring Security + OAuth2 + JWT</code></li><li>需要完整 IAM 系统：<code>Keycloak</code> / <code>Spring Authorization Server</code></li><li>国内轻量项目：<code>Sa-Token + JWT</code>，见 <a href="./sa-token">Sa-Token</a></li></ul>`,12)])])}const g=e(n,[["render",s]]);export{d as __pageData,g as default};
